@page "/board"
@using sv_1ecbbe1cfb814e159358d71dd5bdda5d
@using sv_1ecbbe1cfb814e159358d71dd5bdda5d.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @_error
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Tasks="_allTasks" />
    <BoardSearchBar SearchText="@_searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @foreach (var column in _columns)
        {
            var columnTasks = FilteredTasks.Where(t => t.Status == column.Name).ToList();
            <KanbanColumn ColumnName="@column.Name"
                          Tasks="columnTasks"
                          ShowMoveLeft="column.Index > 0"
                          ShowMoveRight="column.Index < _columns.Length - 1"
                          OnMoveTask="args => HandleMoveTask(args.TaskId, args.Direction, column.Index)"
                          OnAddTask="HandleAddTask" />
        }
    </div>
}

@code {
    private record ColumnDef(string Name, int Index);

    private static readonly ColumnDef[] _columns =
    [
        new("To Do", 0),
        new("In Progress", 1),
        new("Done", 2)
    ];

    private List<TaskItem> _allTasks = new();
    private string _searchText = "";
    private bool _loading = true;
    private string? _error;

    private List<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(_searchText)
            ? _allTasks
            : _allTasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        _loading = true;
        _error = null;
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        _searchText = text;
    }

    private async Task HandleMoveTask(int taskId, KanbanColumn.MoveDirection direction, int currentColumnIndex)
    {
        var newIndex = direction == KanbanColumn.MoveDirection.Left
            ? currentColumnIndex - 1
            : currentColumnIndex + 1;

        if (newIndex < 0 || newIndex >= _columns.Length) return;

        var newStatus = _columns[newIndex].Name;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = _allTasks.First(t => t.Id == taskId);
            var index = _allTasks.IndexOf(task);
            _allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            _allTasks.Add(newTask with { Status = args.Status });
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}

