+        {
+            var columnTasks = FilteredTasks.Where(t => t.Status == column.Name).ToList();
+            <KanbanColumn ColumnName="@column.Name"
+                          Tasks="columnTasks"
+                          ShowMoveLeft="column.Index > 0"
+                          ShowMoveRight="column.Index < _columns.Length - 1"
+                          OnMoveTask="args => HandleMoveTask(args.TaskId, args.Direction, column.Index)"
+                          OnAddTask="HandleAddTask" />
+        }
+    </div>
+}
